import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as s,o,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Yandex 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/yandex.md","filePath":"ko-KR/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ko-KR/upload/yandex.md"};function p(c,e,h,x,b,u){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-채널-추가" tabindex="-1">Yandex 채널 추가 <a class="header-anchor" href="#yandex-채널-추가" aria-label="Permalink to &quot;Yandex 채널 추가&quot;">​</a></h1><p>Yandex 채널은 Yandex Disk를 ImgBed의 저장 위치로 사용합니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Yandex 계정</td><td>Yandex Disk 인증</td></tr><tr><td>Yandex OAuth App</td><td>Client ID와 Client Secret 발급</td></tr><tr><td>ImgBed 도메인</td><td>OAuth 콜백 URL에 사용</td></tr><tr><td>Yandex Disk</td><td>실제 파일 저장 위치</td></tr></tbody></table><h2 id="yandex-oauth-app-만들기" tabindex="-1">Yandex OAuth App 만들기 <a class="header-anchor" href="#yandex-oauth-app-만들기" aria-label="Permalink to &quot;Yandex OAuth App 만들기&quot;">​</a></h2><p>다음 주소를 엽니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><p>로그인이 필요하면 저장 위치로 사용할 Yandex 계정으로 로그인합니다.</p><p>새 앱을 만들고 알아보기 쉬운 이름을 붙입니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-yandex</span></span></code></pre></div><p>콜백 URL에는 다음 값을 넣습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://내도메인/api/oauth/yandex/callback</span></span></code></pre></div><h2 id="권한-확인" tabindex="-1">권한 확인 <a class="header-anchor" href="#권한-확인" aria-label="Permalink to &quot;권한 확인&quot;">​</a></h2><p>ImgBed의 Yandex 연동은 <code>Yandex.Disk REST API</code>의 다음 권한을 사용합니다.</p><table tabindex="0"><thead><tr><th>권한</th><th>용도</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>앱 폴더에 파일 저장</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>파일과 다운로드 링크 읽기</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>업로드, 디렉터리 생성, 삭제</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>용량과 사용량 확인</td></tr></tbody></table><p><code>Yandex ID API</code>의 이름이나 이메일 권한은 필요에 따라 선택합니다. 업로드, 삭제, 용량 확인의 핵심은 위 4개 Disk 권한입니다.</p><p><img src="'+t+'" alt="Yandex Disk 권한" loading="lazy"></p><h2 id="client-id와-secret-기록" tabindex="-1">Client ID와 Secret 기록 <a class="header-anchor" href="#client-id와-secret-기록" aria-label="Permalink to &quot;Client ID와 Secret 기록&quot;">​</a></h2><p>앱을 만든 뒤 다음 값을 복사합니다.</p><table tabindex="0"><thead><tr><th>Yandex 항목</th><th>ImgBed 항목</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Client ID와 Secret" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>Yandex</code>를 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>Yandex Main</code></td></tr><tr><td>Client ID</td><td>Yandex App의 Client ID</td></tr><tr><td>Client Secret</td><td>Yandex App의 Client Secret</td></tr><tr><td>Refresh Token</td><td>처음에는 비워 둠</td></tr><tr><td>루트 디렉터리</td><td>선택 사항. 보통 <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="Yandex 설정" loading="lazy"></p><h2 id="refresh-token-받기" tabindex="-1">Refresh Token 받기 <a class="header-anchor" href="#refresh-token-받기" aria-label="Permalink to &quot;Refresh Token 받기&quot;">​</a></h2><ol><li>ImgBed에서 <code>Token 가져오기</code>를 누릅니다.</li><li>저장 위치로 사용할 Yandex 계정으로 로그인합니다.</li><li>권한을 허용합니다.</li><li>콜백 페이지에 표시된 <code>Refresh Token</code>을 복사합니다.</li><li>ImgBed의 <code>Refresh Token</code> 칸에 붙여 넣습니다.</li></ol><p><img src="'+n+`" alt="Refresh Token" loading="lazy"></p><h2 id="빠른-절차" tabindex="-1">빠른 절차 <a class="header-anchor" href="#빠른-절차" aria-label="Permalink to &quot;빠른 절차&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console 열기</span></span>
<span class="line"><span>-&gt; App 만들기</span></span>
<span class="line"><span>-&gt; https://내도메인/api/oauth/yandex/callback 설정</span></span>
<span class="line"><span>-&gt; Disk 권한 확인</span></span>
<span class="line"><span>-&gt; Client ID / Client Secret 복사</span></span>
<span class="line"><span>-&gt; ImgBed에 입력</span></span>
<span class="line"><span>-&gt; Token 가져오기</span></span>
<span class="line"><span>-&gt; Refresh Token 붙여 넣고 저장</span></span></code></pre></div><h2 id="참고" tabindex="-1">참고 <a class="header-anchor" href="#참고" aria-label="Permalink to &quot;참고&quot;">​</a></h2><ol><li>Yandex 앱 등록: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>인증 코드 URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>OAuth Token API: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,32)])])}const y=s(r,[["render",p]]);export{m as __pageData,y as default};
